export type BookingStatus = "pending" | "confirmed" | "completed" | "cancelled";

export type Booking = {
  id: string;
  email: string;
  service: string;
  date: string;
  time: string;
  status: BookingStatus;
  address: string;
  amount: number;
  instructions?: string;
  assignedTo: string;
  frequency: string;
};

