"use client";

import { useEffect, useMemo, useState } from "react";
import { Card, CardContent, CardHeader } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Search } from "lucide-react";
import { bookingsMock, statusCopy, type Booking, type BookingStatus } from "../data.ts";
import { Calendar } from "lucide-react";

const variantConfig = {
  upcoming: {
    title: "Upcoming Appointments",
    description: "Keep track of your pending and confirmed visits.",
    emptyMessage: "You don't have any upcoming appointments right now.",
  },
  previous: {
    title: "Previous Appointments",
    description: "Review the services you've already completed.",
    emptyMessage: "No completed appointments found.",
  },
  cancelled: {
    title: "Cancelled Appointments",
    description: "See the bookings you've decided to call off.",
    emptyMessage: "No cancelled appointments on record.",
  },
} as const;

export type AppointmentsVariant = keyof typeof variantConfig;

function filterBookings(bookings: Booking[], variant: AppointmentsVariant) {
  if (variant === "upcoming") {
    const startOfToday = new Date(new Date().toDateString());
    return bookings.filter((booking) => {
      const bookingDate = new Date(booking.date);
      return booking.status === "confirmed" && bookingDate >= startOfToday;
    });
  }

  if (variant === "previous") {
    return bookings.filter((booking) => booking.status === "completed");
  }

  if (variant === "cancelled") {
    return bookings.filter((booking) => booking.status === "cancelled");
  }

  return bookings;
}

const dayFormatter = new Intl.DateTimeFormat("en-US", { weekday: "short" });
const dateFormatter = new Intl.DateTimeFormat("en-US", {
  month: "short",
  day: "numeric",
  year: "numeric",
});

function formatDay(dateStr: string) {
  const parsed = new Date(dateStr);
  if (Number.isNaN(parsed.getTime())) return "—";
  return dayFormatter.format(parsed);
}

function formatDate(dateStr: string) {
  const parsed = new Date(dateStr);
  if (Number.isNaN(parsed.getTime())) return dateStr;
  return dateFormatter.format(parsed);
}

const StatusBadge = ({ status }: { status: BookingStatus }) => (
  <Badge className={`inline-flex items-center gap-1 px-2.5 py-1 ${statusCopy[status].tone}`}>
    {statusCopy[status].label}
  </Badge>
);

export function AppointmentsView({ variant }: { variant: AppointmentsVariant }) {
  const sampleEmail = bookingsMock[0]?.email ?? null;
  const [customerEmail, setCustomerEmail] = useState<string | null>(sampleEmail);

  useEffect(() => {
    if (typeof window === "undefined") return;
    const storedEmail = localStorage.getItem("customerEmail");
    setCustomerEmail(storedEmail ?? sampleEmail);
  }, [sampleEmail]);

  const bookings = useMemo(() => {
    if (!customerEmail) return [];
    const customerBookings = bookingsMock.filter((booking) => booking.email === customerEmail);
    return filterBookings(customerBookings, variant);
  }, [customerEmail, variant]);

  const config = variantConfig[variant];
  const isUpcoming = variant === "upcoming";

  return (
    <div className="space-y-6">
      <Card className="border border-border/70 shadow-sm">
        <CardHeader className="border-b border-border/70 pb-4 space-y-4">
          <div>
            <h2 className="text-2xl font-semibold tracking-tight text-foreground">{config.title}</h2>
            <p className="text-sm text-muted-foreground">{config.description}</p>
          </div>

          <div className="flex flex-col gap-3 lg:flex-row lg:items-center lg:justify-between">
            <div className="relative flex-1">
              <Search className="pointer-events-none absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
              <Input placeholder="Search bookings..." className="pl-10" />
            </div>
            {isUpcoming && (
              <Button className="bg-primary text-primary-foreground hover:bg-primary/90">Add Booking</Button>
            )}
          </div>
        </CardHeader>
        <CardContent className="p-0">
          {bookings.length === 0 ? (
            <div className="flex flex-col items-center justify-center gap-3 px-6 py-12 text-center">
              <div className="rounded-full bg-muted p-3">
                <Calendar className="h-5 w-5 text-muted-foreground" />
              </div>
              <div>
                <p className="text-sm text-muted-foreground">{config.emptyMessage}</p>
                <p className="text-xs text-muted-foreground">Check back soon or schedule a new service.</p>
              </div>
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="min-w-[720px] w-full text-sm">
                <thead className="bg-muted/50 text-muted-foreground">
                  <tr>
                    <th className="px-5 py-3 text-left font-medium">Day / Time</th>
                    <th className="px-5 py-3 text-left font-medium">Assigned To</th>
                    <th className="px-5 py-3 text-left font-medium">Service</th>
                    <th className="px-5 py-3 text-left font-medium">Frequency</th>
                    <th className="px-5 py-3 text-left font-medium">Location</th>
                    <th className="px-5 py-3 text-right font-medium">Amount</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-border/70">
                  {bookings.map((booking) => (
                    <tr key={booking.id} className="bg-background">
                      <td className="px-5 py-4 align-top">
                        <p className="text-sm font-semibold text-foreground">{formatDay(booking.date)}</p>
                        <p className="text-xs text-muted-foreground">
                          {formatDate(booking.date)} • {booking.time}
                        </p>
                      </td>
                      <td className="px-5 py-4 align-top text-foreground">{booking.assignedTo}</td>
                      <td className="px-5 py-4 align-top">
                        <p className="font-medium text-foreground">{booking.service}</p>
                        <div className="mt-2">
                          <StatusBadge status={booking.status} />
                        </div>
                      </td>
                      <td className="px-5 py-4 align-top text-foreground">{booking.frequency}</td>
                      <td className="px-5 py-4 align-top text-foreground">{booking.address}</td>
                      <td className="px-5 py-4 align-top text-right text-foreground">
                        <p className="text-lg font-semibold">${booking.amount.toFixed(2)}</p>
                        <p className="text-xs text-muted-foreground">ID: {booking.id}</p>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}
